# Merge using content-based dedup
for pid, obj in local.items():
    new_updates = obj.get('_localUpdates', [])
    for p in data:
        if p['id'] == pid:
            existing = set(u['content'] for u in (p.get('updates') or []))
            added = 0
            for u in new_updates:
                if u['content'] not in existing:
                    p['updates'].append(u)
                    existing.add(u['content'])
                    added += 1
            p['updates'].sort(key=lambda u: u.get('date', ''), reverse=True)
            print(f'{pid}: +{added}, total {len(p["updates"])}')
            break

with open(r'F:\my_docs\PMO管理助理\data\projects.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)
    f.write('\n')
